/* レビューモーダル機能 */
document.addEventListener('DOMContentLoaded', function() {
    var modal = document.getElementById("lpReviewModal");
    var modalImg = document.getElementById("lpModalImg");
    var images = document.querySelectorAll(".lp-review-screenshot");
    var closeBtn = document.querySelector(".lp-modal-close");

    if (!modal || !modalImg || !closeBtn) return;

    images.forEach(function(img) {
        img.style.cursor = "pointer";
        img.addEventListener('click', function(e) {
            modal.style.display = "flex";
            modal.style.alignItems = "center";
            modal.style.justifyContent = "center";
            modalImg.src = e.target.src;
        });
    });

    var closeModal = function() {
        modal.style.display = "none";
    };

    closeBtn.addEventListener('click', closeModal);

    modal.addEventListener('click', function(e) {
        if (e.target === modal) {
            closeModal();
        }
    });

    modalImg.addEventListener('click', closeModal);
});